   167→// NewServer creates handlers from a config watcher and callbacks.
   168→func NewServer(ctx context.Context, config cache.Cache, callbacks Callbacks, opts ...config.XDSOption) Server {
   169→	return NewServerAdvanced(rest.NewServer(config, callbacks),
   170→		sotw.NewServer(ctx, config, callbacks, opts...),
   171→		delta.NewServer(ctx, config, callbacks, opts...),
   172→	)
   173→}
