   121→// DrainResponses reads all responses, but does nothing to them
   122→func (a *AdsTest) DrainResponses() {
   123→	for {
   124→		select {
   125→		case <-a.context.Done():
   126→			return
   127→		case r := <-a.responses:
   128→			log.Infof("drained response %v", r.TypeUrl)
   129→		}
   130→	}
   131→}
